import{_ as r,o as a,c as e,a2 as o}from"./chunks/framework.VxKNwi4m.js";const g=JSON.parse('{"title":"역할 및 권한 관리","description":"","frontmatter":{},"headers":[],"relativePath":"work-setting/roll-perm.md","filePath":"work-setting/roll-perm.md","lastUpdated":1783185876000}'),t={name:"work-setting/roll-perm.md"};function i(s,l,n,h,d,u){return a(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="역할-및-권한-관리" tabindex="-1">역할 및 권한 관리 <a class="header-anchor" href="#역할-및-권한-관리" aria-label="Permalink to &quot;역할 및 권한 관리&quot;">​</a></h1><p>이 페이지는 프로젝트 내 사용자의 **역할(Role)**을 정의하고, 각 역할별로 수행 가능한 **권한(Permission)**을 설정하는 공간입니다. 레드마인(Redmine)의 권한 관리 시스템을 모델로 하여, 복잡한 업무 환경에서도 유연하게 접근 제어를 할 수 있도록 설계되었습니다.</p><h2 id="_1-역할-roles-탭" tabindex="-1">1. 역할 (Roles) 탭 <a class="header-anchor" href="#_1-역할-roles-탭" aria-label="Permalink to &quot;1. 역할 (Roles) 탭&quot;">​</a></h2><p>시스템에서 사용할 역할의 종류를 정의하고 기본 속성을 관리합니다.</p><h3 id="역할-목록" tabindex="-1">역할 목록 <a class="header-anchor" href="#역할-목록" aria-label="Permalink to &quot;역할 목록&quot;">​</a></h3><ul><li>등록된 모든 역할의 이름과 업무 위탁 권한 여부를 확인할 수 있습니다.</li><li>역할을 클릭하거나 <strong>[수정]</strong> 버튼을 눌러 상세 설정을 변경할 수 있습니다.</li><li><strong>[새 역할]</strong> 버튼을 통해 새로운 시스템 역할을 추가할 수 있습니다.</li></ul><h3 id="역할-생성-및-수정-모달" tabindex="-1">역할 생성 및 수정 (모달) <a class="header-anchor" href="#역할-생성-및-수정-모달" aria-label="Permalink to &quot;역할 생성 및 수정 (모달)&quot;">​</a></h3><p>역할의 핵심 속성을 설정합니다.</p><ul><li><strong>이름</strong>: 역할의 명칭 (예: 관리자, 개발자, 기획자 등).</li><li><strong>업무 위탁 권한</strong>: 이 역할을 가진 사용자가 업무를 다른 사람에게 위탁(할당)받을 수 있는지 여부.</li><li><strong>업무 보기 권한</strong>: 이 역할이 볼 수 있는 업무의 범위를 설정합니다. <ul><li><em>모든 업무 / 비공개 업무 제외 / 직접 생성 또는 담당한 업무 / 없음</em></li></ul></li><li><strong>사용자 보기 권한</strong>: 프로젝트 내 다른 사용자를 볼 수 있는 범위를 설정합니다. <ul><li><em>모든 활성 사용자 / 보이는 프로젝트 사용자 / 없음</em></li></ul></li></ul><blockquote><p><strong>Tip</strong>: 역할 생성/수정 모달에서는 기본 속성만 설정합니다. 세부적인 기능 권한은 <strong>&#39;권한 보고서&#39;</strong> 탭에서 설정해 주세요.</p></blockquote><h2 id="_2-권한-보고서-permission-report-탭" tabindex="-1">2. 권한 보고서 (Permission Report) 탭 <a class="header-anchor" href="#_2-권한-보고서-permission-report-탭" aria-label="Permalink to &quot;2. 권한 보고서 (Permission Report) 탭&quot;">​</a></h2><p>정의된 각 역할에 대해 구체적으로 어떤 기능(모듈)을 사용할 수 있는지 매트릭스 형태로 한눈에 관리합니다.</p><h3 id="매트릭스-구조" tabindex="-1">매트릭스 구조 <a class="header-anchor" href="#매트릭스-구조" aria-label="Permalink to &quot;매트릭스 구조&quot;">​</a></h3><ul><li><strong>가로축 (상단)</strong>: 정의된 역할(Role) 목록.</li><li><strong>세로축 (좌측)</strong>: 기능 모듈별 권한 목록. <ul><li>프로젝트 관리, 업무, 회의, 공지, 문서, 게시판, 달력 등 각 모듈별로 세분화되어 있습니다.</li></ul></li></ul><h3 id="권한-설정-방법" tabindex="-1">권한 설정 방법 <a class="header-anchor" href="#권한-설정-방법" aria-label="Permalink to &quot;권한 설정 방법&quot;">​</a></h3><ul><li>각 역할과 권한이 교차하는 지점의 <strong>체크박스</strong>를 클릭하면 즉시 반영됩니다.</li><li>권한 항목 아래의 설명을 참고하여 필요한 권한만 최소한으로 부여하는 것이 보안상 좋습니다.</li></ul><h2 id="_3-권한-관리-워크플로우-권장" tabindex="-1">3. 권한 관리 워크플로우 (권장) <a class="header-anchor" href="#_3-권한-관리-워크플로우-권장" aria-label="Permalink to &quot;3. 권한 관리 워크플로우 (권장)&quot;">​</a></h2><ol><li><strong>역할 정의</strong>: &#39;역할&#39; 탭에서 우리 팀의 구성에 맞는 역할들을 먼저 만듭니다. (예: 매니저, 팀원, 외부 파트너)</li><li><strong>세부 권한 할당</strong>: &#39;권한 보고서&#39; 탭으로 이동하여 각 역할이 어떤 기능을 사용할 수 있는지 체크합니다.</li><li><strong>사용자 연결</strong>: 프로젝트 설정의 &#39;구성원&#39; 메뉴에서 실제 사용자에게 이 역할들을 부여합니다.</li></ol><h2 id="주의사항" tabindex="-1">주의사항 <a class="header-anchor" href="#주의사항" aria-label="Permalink to &quot;주의사항&quot;">​</a></h2><ul><li>역할을 삭제하면 해당 역할을 부여받은 모든 사용자의 권한이 상실되므로 신중하게 결정해야 합니다.</li><li>삭제 전 반드시 해당 역할을 사용 중인 구성원이 있는지 확인해 주세요.</li></ul>',20)])])}const m=r(t,[["render",i]]);export{g as __pageData,m as default};
